      if (!copyAFile(snapDir, indexDir, fname, copiedfiles)) return false;
      copiedfiles.add(fname);
    }
    if (segmentsFile != null) {
      if (!copyAFile(snapDir, indexDir, segmentsFile, copiedfiles)) return false;
    }
    return true;
  }

